function sanitizeJsonNode(value, current = 0) {
  if (current >= MAX_DEPTH) return undefined;
  if (Array.isArray(value)) {
    return value.slice(0, MAX_FANOUT).map((entry) => sanitizeJsonNode(entry, current + 1));
  }
  if (value && typeof value === "object") {
    const next = {};
    Object.entries(value).forEach(([key, entryValue]) => {
      next[key] = sanitizeJsonNode(entryValue, current + 1);
    });
    return next;
  }
  return value;
}
